+import { $internal } from '../common';
+import { destroyEntity, materializeEntity } from '../entity/entity';
+import type { Entity } from '../entity/types';
+import { allocateEntity, isEntityAlive, releaseEntity } from '../entity/utils/entity-index';
+import type { RelationPair } from '../relation/types';
+import { hasRelationPair } from '../relation/relation';
+import { isRelationPair } from '../relation/utils/is-relation';
+import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
+import type { ConfigurableTrait, Trait } from '../trait/types';
+import type { DeferredCommand, DeferredWorld, World } from './types';
+
+function current(world: World): DeferredCommand[] {
+    const buffers = world[$internal].deferred.buffers;
+    return buffers[buffers.length - 1];
+}
+
+function commandsFor(world: World, entity: Entity): DeferredCommand[] {
+    return world[$internal].deferred.buffers.flatMap((buffer) =>
+        buffer.filter((command) => command.entity === entity)
+    );
+}
+
+/** Begin/end are intentionally internal: query iteration owns nested scopes. */
+export function beginDeferredScope(world: World) {
+    world[$internal].deferred.buffers.push([]);
+}
+
+export function endDeferredScope(world: World) {
+    const state = world[$internal].deferred;
+    const buffer = state.buffers.pop()!;
+    execute(world, buffer);
+}
+
+export function createDeferredWorld(world: World): DeferredWorld {
+    return {
+        spawn(...traits) {
+            const entity = allocateEntity(world[$internal].entityIndex);
+            world[$internal].deferred.reserved.add(entity);
+            current(world).push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) {
+            current(world).push({ type: 'destroy', entity });
+        },
+        add(entity, ...traits) {
+            current(world).push({ type: 'add', entity, traits });
+        },
+        remove(entity, ...traits) {
+            current(world).push({ type: 'remove', entity, traits });
+        },
+        addExclusive(entity, ...pairs) {
+            current(world).push({ type: 'addExclusive', entity, pairs });
+        },
+        flush() {
+            const buffer = current(world);
+            current(world).length = 0;
+            execute(world, buffer);
+        },
+    };
+}
+
+export function hasDeferredEntity(world: World, entity: Entity): boolean {
+    const state = world[$internal].deferred;
+    if (state.isExecuting) return isEntityAlive(world[$internal].entityIndex, entity);
+    let alive = isEntityAlive(world[$internal].entityIndex, entity);
+    for (const command of commandsFor(world, entity)) {
+        if (command.type === 'destroy') alive = false;
+        if (command.type === 'spawn') alive = true;
+    }
+    return alive;
+}
+
+/** Read the projected presence of a trait or relation pair without applying commands. */
+export function hasDeferredTrait(world: World, entity: Entity, target: Trait | RelationPair): boolean {
+    const state = world[$internal].deferred;
+    if (state.isExecuting || commandsFor(world, entity).length === 0) {
+        return isRelationPair(target)
+            ? hasRelationPair(world, entity, target)
+            : hasTrait(world, entity, target);
+    }
+    if (!hasDeferredEntity(world, entity)) return false;
+
+    let present = isRelationPair(target)
+        ? hasRelationPair(world, entity, target)
+        : hasTrait(world, entity, target);
+    for (const command of commandsFor(world, entity)) {
+        if (command.type === 'destroy') return false;
+        if (command.type === 'add') {
+            for (const config of command.traits) {
+                if (sameTarget(config, target)) present = true;
+            }
+        } else if (command.type === 'remove') {
+            for (const remove of command.traits) {
+                if (removesTarget(remove, target)) present = false;
+            }
+        } else if (command.type === 'addExclusive') {
+            for (const pair of command.pairs) {
+                if (isRelationPair(target) && pair[$internal].relation === target[$internal].relation) {
+                    present = pair[$internal].target !== '*' && sameTarget(pair, target);
+                }
+            }
+        }
+    }
+    return present;
+}
+
+export function getDeferredTrait(world: World, entity: Entity, target: Trait | RelationPair): any {
+    if (!hasDeferredTrait(world, entity, target)) return undefined;
+    let value = getTrait(world, entity, target);
+    for (const command of commandsFor(world, entity)) {
+        if (command.type === 'add') {
+            for (const config of command.traits) {
+                if (sameTarget(config, target)) value = configurationValue(config) ?? value;
+            }
+        }
+    }
+    return value;
+}
+
+/** Flush commands addressing one entity before a direct mutation of it. */
+export function flushDeferredEntity(world: World, entity: Entity) {
+    const state = world[$internal].deferred;
+    if (state.isExecuting) return;
+    for (const buffer of state.buffers) {
+        const selected = buffer.filter((command) => command.entity === entity);
+        if (selected.length === 0) continue;
+        for (let i = buffer.length - 1; i >= 0; i--) {
+            if (buffer[i].entity === entity) buffer.splice(i, 1);
+        }
+        execute(world, selected);
+    }
+}
+
+function execute(world: World, input: DeferredCommand[]) {
+    const state = world[$internal].deferred;
+    // A deferred spawn followed by its destruction never becomes observable.
+    const nullified = new Set<Entity>();
+    const spawned = new Set(input.filter((command) => command.type === 'spawn').map((command) => command.entity));
+    for (const command of input) {
+        if (command.type === 'destroy' && spawned.has(command.entity)) nullified.add(command.entity);
+    }
+
+    state.isExecuting = true;
+    try {
+        for (const command of input) {
+            if (nullified.has(command.entity)) continue;
+            if (command.type === 'spawn') {
+                if (isEntityAlive(world[$internal].entityIndex, command.entity)) {
+                    materializeEntity(world, command.entity, ...command.traits);
+                    state.reserved.delete(command.entity);
+                }
+                continue;
+            }
+            if (!isEntityAlive(world[$internal].entityIndex, command.entity)) continue;
+            if (command.type === 'destroy') {
+                if (command.entity === world[$internal].worldEntity) {
+                    throw new Error('Koota: The world entity cannot be destroyed through deferred commands.');
+                }
+                destroyEntity(world, command.entity);
+            } else if (command.type === 'add') {
+                applyAdd(world, command.entity, command.traits);
+            } else if (command.type === 'remove') {
+                removeTrait(world, command.entity, ...command.traits);
+            } else {
+                for (const pair of command.pairs) {
+                    if (pair[$internal].target === '*') removeTrait(world, command.entity, pair);
+                    else {
+                        removeTrait(world, command.entity, pair[$internal].relation('*'));
+                        applyAdd(world, command.entity, [pair]);
+                    }
+                }
+            }
+        }
+    } finally {
+        state.isExecuting = false;
+        for (const entity of nullified) {
+            if (isEntityAlive(world[$internal].entityIndex, entity)) releaseEntity(world[$internal].entityIndex, entity);
+            state.reserved.delete(entity);
+        }
+    }
+}
+
+function applyAdd(world: World, entity: Entity, traits: ConfigurableTrait[]) {
+    for (const config of traits) {
+        const target = Array.isArray(config) ? config[0] : config;
+        const existed = isRelationPair(target)
+            ? hasRelationPair(world, entity, target)
+            : hasTrait(world, entity, target as Trait);
+        addTrait(world, entity, config);
+        if (existed) {
+            const value = configurationValue(config);
+            if (value !== undefined) setTrait(world, entity, target as Trait | RelationPair, value, false);
+        }
+    }
+}
+
+function configurationValue(config: ConfigurableTrait): any {
+    if (Array.isArray(config)) return config[1];
+    if (isRelationPair(config)) return config[$internal].params;
+    return undefined;
+}
+
+function sameTarget(config: ConfigurableTrait, target: Trait | RelationPair): boolean {
+    const actual = Array.isArray(config) ? config[0] : config;
+    if (isRelationPair(actual) || isRelationPair(target)) {
+        return (
+            isRelationPair(actual) &&
+            isRelationPair(target) &&
+            actual[$internal].relation === target[$internal].relation &&
+            actual[$internal].target === target[$internal].target
+        );
+    }
+    return actual === target;
+}
+
+function removesTarget(remove: Trait | RelationPair, target: Trait | RelationPair): boolean {
+    if (!isRelationPair(remove) || !isRelationPair(target)) return remove === target;
+    return (
+        remove[$internal].relation === target[$internal].relation &&
+        (remove[$internal].target === '*' || remove[$internal].target === target[$internal].target)
+    );
+}
